class ProgressTracker{constructor(){this.sessionId=null;this.pollInterval=null;this.isActive=false}generateSessionId(){return'session_'+Date.now()+'_'+Math.random().toString(36).substr(2,9)}startTracking(e,t,s,n){this.sessionId=e||this.generateSessionId();this.isActive=true;if(this.pollInterval){clearInterval(this.pollInterval)}this.pollInterval=setInterval(async()=>{if(!this.isActive){clearInterval(this.pollInterval);return}try{const e=await fetch(`/progress/${this.sessionId}`);if(e.ok){const i=await e.json();if(i&&i.success){this.updateProgress(i,t,s);if(i.status==='done'||i.percent>=100){this.stopTracking();if(n)n(i)}}}}catch(e){}},500);return this.sessionId}updateProgress(e,t,s){if(!e)return;const n=Math.max(0,Math.min(100,e.percent||0)),i=e.status||'processing',o=e.currentFile||'';if(t){t.style.width=`${n}%`}if(s){let e='';if(i==='processing'){e=`Converting... ${n}%`;if(o){e+=` (${o})`}}else if(i==='done'){e='Conversion completed!'}else if(i==='queued'){e='Starting conversion...'}else{e=`${i} ${n}%`}s.textContent=e}console.log(`📊 Progress: ${n}% - ${i}${o?` - ${o}`:''}`)}stopTracking(){this.isActive=false;if(this.pollInterval){clearInterval(this.pollInterval);this.pollInterval=null}console.log(`⏹️ Stopped progress tracking for session: ${this.sessionId}`)}uploadWithProgress(e,t,s,n,i,o,r){const l=new XMLHttpRequest;const a=this.generateSessionId();e.append('clientSessionId',a);l.open('POST','/convert');l.timeout=18e5;l.upload.addEventListener('progress',e=>{if(e.lengthComputable&&t&&s){const n=Math.round(e.loaded/e.total*100);t.style.width=`${n}%`;s.textContent=`Uploading... ${n}%`;console.log(`📤 Upload: ${n}%`)}});l.onload=()=>{if(t&&s){t.style.width='100%';s.textContent='Upload complete. Starting conversion...'}if(l.status===200){try{const t=JSON.parse(l.responseText);if(n&&i){i.style.width='0%';i.textContent='Converting... 0%';this.startTracking(a,i,n,e=>{if(o)o(t)})}else{if(o)o(t)}}catch(e){console.error('Error parsing response:',e);if(r)r('Invalid response from server')}}else{if(r)r(`Upload failed: ${l.status}`)}};l.onerror=()=>{if(r)r('Upload failed')};l.ontimeout=()=>{if(r)r('Request timeout - file too large or conversion taking too long')};l.send(e);return a}}window.ProgressTracker=new ProgressTracker;

